#ifndef DMA_HAL_H
#define DMA_HAL_H

#include <stdint.h>

typedef void (*DMA_Callback_t)(void);

typedef struct {
    uint32_t       src_addr;
    uint32_t       dst_addr;
    uint32_t       length;
    uint8_t        src_width;   /* 1, 2, or 4 bytes */
    uint8_t        dst_width;   /* 1, 2, or 4 bytes */
    uint8_t        burst_size;
    DMA_Callback_t complete_cb;
    DMA_Callback_t error_cb;
} DMA_Transfer_t;

int  DMA_Init(uint8_t channel);
int  DMA_Start(uint8_t channel, DMA_Transfer_t *xfer);
void DMA_Abort(uint8_t channel);
uint8_t DMA_IsBusy(uint8_t channel);
uint32_t DMA_GetBytesRemaining(uint8_t channel);
void DMA_Deinit(uint8_t channel);

#endif /* DMA_HAL_H */

